#!/usr/bin/env Rscript
#
# benchmark_R.R - R countdata benchmark on the SAME data generated by benchmark_python.py.
#
# Run benchmark_python.py FIRST to generate bench_x.csv, bench_tx.csv, bench_group.csv.
#
# Usage:
#   conda activate countdata
#   python3 benchmark_python.py   # generates shared data
#   Rscript benchmark_R.R

library(countdata)

N_THREADS <- 48L

# --- Load shared data ---
cat("Loading data generated by benchmark_python.py ...\n")

if (!file.exists("bench_x.csv")) {
  stop("bench_x.csv not found. Run benchmark_python.py first.")
}

x     <- as.matrix(read.csv("bench_x.csv", header = FALSE))
tx    <- as.matrix(read.csv("bench_tx.csv", header = FALSE))
group <- as.integer(read.csv("bench_group.csv", header = FALSE))

N_GENES   <- nrow(x)
N_SAMPLES <- ncol(x)
cat(sprintf("Data: %d genes x %d samples, %d threads\n", N_GENES, N_SAMPLES, N_THREADS))
cat(sprintf("Counts: min=%.0f, median=%.0f, max=%.0f\n\n", min(x), median(x), max(x)))

# --- bb.test ---
cat(strrep("=", 50), "\n")
cat("bb.test (unpaired)\n")
cat(strrep("=", 50), "\n")

t0 <- proc.time()["elapsed"]
bb_res <- bb.test(x, tx, group, n.threads = N_THREADS, verbose = TRUE)
bb_time <- as.numeric(proc.time()["elapsed"] - t0)

bb_p <- bb_res$p.value
cat(sprintf("Time:       %.3f s\n", bb_time))
cat(sprintf("Sig p<0.05: %d/%d\n", sum(bb_p < 0.05), N_GENES))
cat(sprintf("Sig p<0.01: %d/%d\n", sum(bb_p < 0.01), N_GENES))
cat("First 5 p: ", sprintf("%.6e", bb_p[1:5]), "\n\n")

# --- ibb.test ---
cat(strrep("=", 50), "\n")
cat("ibb.test (paired)\n")
cat(strrep("=", 50), "\n")

t0 <- proc.time()["elapsed"]
ibb_res <- ibb.test(x, tx, group, n.threads = N_THREADS, verbose = TRUE)
ibb_time <- as.numeric(proc.time()["elapsed"] - t0)

ibb_p  <- ibb_res$p.value
ibb_fc <- ibb_res$fc
cat(sprintf("Time:       %.3f s\n", ibb_time))
cat(sprintf("Sig p<0.05: %d/%d\n", sum(ibb_p < 0.05), N_GENES))
cat(sprintf("Sig p<0.01: %d/%d\n", sum(ibb_p < 0.01), N_GENES))
cat("First 5 p: ", sprintf("%.6e", ibb_p[1:5]), "\n")
cat("First 5 fc:", sprintf("%.4f", ibb_fc[1:5]), "\n\n")

# --- Save p-values for comparison ---
write.csv(data.frame(p = bb_p),  "bench_bb_pvals_R.csv",  row.names = FALSE)
write.csv(data.frame(p = ibb_p), "bench_ibb_pvals_R.csv", row.names = FALSE)
write.csv(data.frame(fc = ibb_fc), "bench_ibb_fc_R.csv",  row.names = FALSE)

out <- data.frame(bb_sec = round(bb_time, 4), ibb_sec = round(ibb_time, 4),
                  bb_sig005 = sum(bb_p < 0.05), ibb_sig005 = sum(ibb_p < 0.05))
write.csv(out, "bench_results_R.csv", row.names = FALSE)

cat(sprintf("Summary: bb=%.3fs  ibb=%.3fs\n", bb_time, ibb_time))